$parsed = wp_parse_url( $url );
$host = $parsed['host'] ?? '';
// Block link-local IMDS
$ip = gethostbyname( $host );
if ( preg_match( '/^169\.254\./', $ip ) ) {
    return new WP_Error( 'http_request_failed', 'Blocked: link-local address' );
